import axios from "axios";
import "./PriceList.css";

const API_URL = "http://localhost:7000/api/prices";
const CATEGORY_URL = "http://localhost:7000/api/categories";

export default function PriceList() {
  const [items, setItems] = useState([]);
  const [categories, setCategories] = useState([]);
  const [form, setForm] = useState({
    name: "",
    category: "",
    description: "",
    basePrice: "",
    difference: "",
    validTill: "",
    file: null,
  });
  const [editId, setEditId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [csvFile, setCsvFile] = useState(null);
  const [addingCategory, setAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState("");
  const csvInputRef = useRef();

  useEffect(() => {
    fetchItems();
    fetchCategories();
  }, []);

  const fetchItems = async () => {
    setLoading(true);
    try {
      const res = await axios.get(API_URL);
      if (res.data.success) setItems(res.data.data);
    } catch (err) {
      console.error("Error fetching items:", err);
    } finally {
      setLoading(false);
    }
  };

  const fetchCategories = async () => {
    try {
      const res = await axios.get(CATEGORY_URL);
      if (res.data.success) setCategories(res.data.categories);
    } catch (err) {
      console.error("Error fetching categories:", err);
    }
  };

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    if (files) setForm({ ...form, file: files[0] });
    else setForm({ ...form, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (!form.name || !form.category || !form.basePrice) {
        alert("Name, category, and base price are required");
        setLoading(false);
        return;
      }

      const fd = new FormData();
      Object.keys(form).forEach((key) => {
        if (form[key]) fd.append(key, form[key]);
      });

      if (editId) await axios.put(`${API_URL}/${editId}`, fd);
      else await axios.post(API_URL, fd);

      setForm({
        name: "",
        category: "",
        description: "",
        basePrice: "",
        difference: "",
        validTill: "",
        file: null,
      });
      setEditId(null);
      fetchItems();
    } catch (err) {
      console.error("Error saving price:", err);
      alert("Failed to save price.");
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (item) => {
    setForm({
      name: item.name,
      category: item.category?._id || "",
      description: item.description || "",
      basePrice: item.basePrice,
      difference: item.difference,
      validTill: item.validTill ? item.validTill.split("T")[0] : "",
      file: null,
    });
    setEditId(item._id);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this item?")) return;
    setLoading(true);
    try {
      await axios.delete(`${API_URL}/${id}`);
      fetchItems();
    } catch (err) {
      console.error("Error deleting item:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
    setForm({
      name: "",
      category: "",
      description: "",
      basePrice: "",
      difference: "",
      validTill: "",
      file: null,
    });
    setEditId(null);
  };

  // Add category inline
  const handleAddCategory = async () => {
    if (!newCategoryName.trim()) return alert("Enter category name");
    try {
      const res = await axios.post(CATEGORY_URL, { name: newCategoryName.trim() });
      if (res.data.success) {
        setNewCategoryName("");
        setAddingCategory(false);
        fetchCategories();
        alert("Category added successfully!");
      } else {
        alert(res.data.message || "Failed to add category");
      }
    } catch (err) {
      console.error("Add category error:", err);
      alert("Add category failed");
    }
  };

  // CSV Import
  const handleCsvSelect = (e) => setCsvFile(e.target.files[0]);

  const handleImportCsv = async () => {
    if (!csvFile) return alert("Choose a CSV file first");
    const fd = new FormData();
    fd.append("file", csvFile);
    setLoading(true);
    try {
      const res = await axios.post(`${API_URL}/import`, fd, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      if (res.data.success) {
        alert(`Imported ${res.data.inserted || 0} items`);
        fetchItems();
        setCsvFile(null);
        if (csvInputRef.current) csvInputRef.current.value = null;
      } else alert("Import failed, check file format");
    } catch (err) {
      console.error("Import error:", err);
      alert("Import failed");
    } finally {
      setLoading(false);
    }
  };

  // CSV Export
  const handleExportCsv = async () => {
    try {
      setLoading(true);
      const res = await axios.get(`${API_URL}/export`, { responseType: "blob" });
      const blob = new Blob([res.data], { type: "text/csv;charset=utf-8;" });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `prices_export_${Date.now()}.csv`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);
    } catch (err) {
      console.error("Export error:", err);
      alert("Export failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="price-container">
      <div className="header-section">
        <h1>💰 Price Management</h1>
        <p>Manage prices, import/export CSV, and add new categories easily.</p>
      </div>

      {/* Add/Edit Form */}
      <div className="price-form-card">
        <h2>{editId ? "✏️ Edit Price" : "➕ Add New Price"}</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-grid">
            <div className="form-group">
              <label>Product Name *</label>
              <input name="name" value={form.name} onChange={handleChange} placeholder="Enter name" required />
            </div>

            <div className="form-group">
              <label>Category *</label>
              <div className="category-row">
                <select name="category" value={form.category} onChange={handleChange} required>
                  <option value="">Select Category</option>
                  {categories.map((cat) => (
                    <option key={cat._id} value={cat._id}>
                      {cat.name}
                    </option>
                  ))}
                </select>
                <button
                  type="button"
                  className="btn small"
                  onClick={() => setAddingCategory(!addingCategory)}
                >
                  {addingCategory ? "Close" : "Add"}
                </button>
              </div>
            </div>

            {addingCategory && (
              <div className="form-group full-width">
                <label>New Category</label>
                <div className="category-row">
                  <input
                    value={newCategoryName}
                    onChange={(e) => setNewCategoryName(e.target.value)}
                    placeholder="Enter new category"
                  />
                  <button
                    type="button"
                    className="btn primary"
                    onClick={handleAddCategory}
                  >
                    Create
                  </button>
                </div>
              </div>
            )}

            <div className="form-group">
              <label>Base Price (₹) *</label>
              <input
                type="number"
                name="basePrice"
                value={form.basePrice}
                onChange={handleChange}
                required
              />
            </div>

            <div className="form-group">
              <label>Difference (₹)</label>
              <input
                type="number"
                name="difference"
                value={form.difference}
                onChange={handleChange}
              />
            </div>

            <div className="form-group">
              <label>Valid Till</label>
              <input
                type="date"
                name="validTill"
                value={form.validTill}
                onChange={handleChange}
              />
            </div>

            <div className="form-group">
              <label>Image</label>
              <input type="file" name="file" onChange={handleChange} accept="image/*" />
            </div>
          </div>

          <div className="form-group full-width">
            <label>Description</label>
            <textarea
              name="description"
              value={form.description}
              onChange={handleChange}
              placeholder="Write product details..."
            />
          </div>

          <div className="form-actions">
            <button type="submit" className="btn primary" disabled={loading}>
              {loading ? "Saving..." : editId ? "Update Price" : "Add Price"}
            </button>
            {editId && (
              <button type="button" className="btn cancel" onClick={handleCancel}>
                Cancel
              </button>
            )}
          </div>
        </form>
      </div>

      {/* CSV Section */}
      <div className="csv-controls">
        <div>
          <input
            type="file"
            accept=".csv,text/csv"
            ref={csvInputRef}
            onChange={handleCsvSelect}
          />
          <button className="btn small" onClick={handleImportCsv}>
            📥 Import CSV
          </button>
        </div>
        <div>
          <button className="btn primary" onClick={handleExportCsv}>
            📤 Export CSV
          </button>
        </div>
      </div>

      {/* Table */}
      <div className="table-card">
        <div className="table-header">
          <h2>📋 Price List</h2>
          <span>Total: {items.length}</span>
        </div>

        {loading ? (
          <div className="loader">Loading...</div>
        ) : items.length === 0 ? (
          <p className="empty">No data found</p>
        ) : (
          <table>
            <thead>
              <tr>
                <th>Image</th>
                <th>Name</th>
                <th>Category</th>
                <th>Base Price</th>
                <th>Diff</th>
                <th>Final</th>
                <th>Valid Till</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {items.map((item) => (
                <tr key={item._id}>
                  <td>
                    {item.image ? (
                      <img src={item.image} alt={item.name} />
                    ) : (
                      <span className="no-img">No Img</span>
                    )}
                  </td>
                  <td>{item.name}</td>
                  <td>{item.category?.name || "N/A"}</td>
                  <td>₹{item.basePrice}</td>
                  <td>{item.difference || 0}</td>
                  <td>₹{item.basePrice + (item.difference || 0)}</td>
                  <td>
                    {item.validTill
                      ? new Date(item.validTill).toLocaleDateString("en-IN")
                      : "-"}
                  </td>
                  <td className="actions">
                    <button className="btn edit" onClick={() => handleEdit(item)}>
                      Edit
                    </button>
                    <button
                      className="btn delete"
                      onClick={() => handleDelete(item._id)}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
